 931 /// Returns a pointer into the coroutine frame at the offset where Orig is
 932 /// located.
 933 static Value *createGEPToFramePointer(const FrameDataInfo &FrameData,
 934                                       IRBuilder<> &Builder, coro::Shape &Shape,
 935                                       Value *Orig) {
 936   LLVMContext &Ctx = Shape.CoroBegin->getContext();
 937   uint64_t Offset = FrameData.getOffset(Orig);
 938   auto *OffsetVal = ConstantInt::get(Type::getInt64Ty(Ctx), Offset);
 939   Value *Ptr = Builder.CreateInBoundsPtrAdd(Shape.FramePtr, OffsetVal);
 940 
 941   if (auto *AI = dyn_cast<AllocaInst>(Orig)) {
 942     if (FrameData.getDynamicAlign(Orig) != 0) {
 943       assert(FrameData.getDynamicAlign(Orig) == AI->getAlign().value());
 944       auto *M = AI->getModule();
 945       auto *IntPtrTy = M->getDataLayout().getIntPtrType(AI->getType());
 946       auto *PtrValue = Builder.CreatePtrToInt(Ptr, IntPtrTy);
 947       auto *AlignMask = ConstantInt::get(IntPtrTy, AI->getAlign().value() - 1);
 948       PtrValue = Builder.CreateAdd(PtrValue, AlignMask);
 949       PtrValue = Builder.CreateAnd(PtrValue, Builder.CreateNot(AlignMask));
 950       return Builder.CreateIntToPtr(PtrValue, AI->getType());
 951     }
 952     // If the type of Ptr is not equal to the type of AllocaInst, it implies
 953     // that the AllocaInst may be reused in the Frame slot of other AllocaInst.
 954     // Note: If the strategy dealing with alignment changes, this cast must be
 955     // refined
 956     if (Ptr->getType() != Orig->getType())
 957       Ptr = Builder.CreateAddrSpaceCast(Ptr, Orig->getType(),
 958                                         Orig->getName() + Twine(".cast"));
 959   }
 960   return Ptr;
 961 }
